#include "AnalysisEngine.h"
#include <cmath>
namespace referencelab {
float AnalysisEngine::db(float v)noexcept{return juce::Decibels::gainToDecibels(juce::jmax(v,1.0e-5f),-100.f);}float AnalysisEngine::lufs(double e)noexcept{return e>1.0e-10?static_cast<float>(-0.691+10.0*std::log10(e)):-100.f;}
void AnalysisEngine::prepare(double sr)noexcept{rate=sr>0?sr:44100.0;reset();}void AnalysisEngine::reset()noexcept{integratedEnergy=integratedSamples=0;momentaryEnergy=shortEnergy=0;previousL=previousR=0;}
void AnalysisEngine::process(const juce::AudioBuffer<float>&b)noexcept{if(b.getNumChannels()==0||b.getNumSamples()==0)return;double sum=0,sumL=0,sumR=0,sumLR=0,sumMid=0,sumSide=0;float p=0,tp=0;for(int i=0;i<b.getNumSamples();++i){auto l=b.getSample(0,i),r=b.getNumChannels()>1?b.getSample(1,i):l;p=juce::jmax(p,juce::jmax(std::abs(l),std::abs(r)));for(int k=1;k<=4;++k){auto t=k*.25f;tp=juce::jmax(tp,juce::jmax(std::abs(juce::jmap(t,previousL,l)),std::abs(juce::jmap(t,previousR,r))));}previousL=l;previousR=r;sum+=.5*(l*l+r*r);sumL+=l*l;sumR+=r*r;sumLR+=l*r;auto m=.5*(l+r),s=.5*(l-r);sumMid+=m*m;sumSide+=s*s;}auto n=(double)b.getNumSamples();auto energy=sum/n;auto blockSeconds=n/rate;auto momentAlpha=1.0-std::exp(-blockSeconds/.4),shortAlpha=1.0-std::exp(-blockSeconds/3.0);momentaryEnergy+=(float)(momentAlpha*(energy-momentaryEnergy));shortEnergy+=(float)(shortAlpha*(energy-shortEnergy));integratedEnergy+=sum;integratedSamples+=n;auto rmsGain=std::sqrt(energy);auto peakDb=db(p);peak.store(peakDb);truePeak.store(db(juce::jmax(p,tp)));rms.store(db((float)rmsGain));crest.store(peakDb-db((float)rmsGain));momentary.store(lufs(momentaryEnergy));shortTerm.store(lufs(shortEnergy));integrated.store(lufs(integratedEnergy/integratedSamples));auto denom=std::sqrt(sumL*sumR);correlation.store(denom>1e-12?(float)juce::jlimit(-1.0,1.0,sumLR/denom):0.f);width.store((float)juce::jlimit(0.0,1.0,std::sqrt(sumSide/(sumMid+sumSide+1e-12))));}
MeterSnapshot AnalysisEngine::snapshot()const noexcept{return{peak.load(),truePeak.load(),rms.load(),crest.load(),momentary.load(),shortTerm.load(),integrated.load(),correlation.load(),width.load()};}
}
